"use client";

import React from "react";
import {
  BlogMarkdownRenderer,
  type BlogMarkdownRendererProps,
} from "./BlogMarkdownRenderer";

/**
 * MarkdownRenderer — 通用 Markdown 渲染器
 *
 * 基于博客场景预设的默认出口：
 * - 支持 GFM、原始 HTML、标题锚点和表格
 * - 内置 CodeBlock、ImageViewer、Mermaid 图表渲染
 * - 可通过 components / widgetRegistry 扩展渲染能力
 *
 * @example
 * ```tsx
 * <MarkdownRenderer content={"# 标题\n\n这是一段 **Markdown**。"} />
 * ```
 */
export function MarkdownRenderer(props: BlogMarkdownRendererProps) {
  return <BlogMarkdownRenderer {...props} />;
}

export default MarkdownRenderer;

export { BlogMarkdownRenderer } from "./BlogMarkdownRenderer";
export { ChatMarkdownRenderer } from "./ChatMarkdownRenderer";
export type { BlogMarkdownRendererProps } from "./BlogMarkdownRenderer";
export type { ChatMarkdownRendererProps } from "./ChatMarkdownRenderer";
export type {
  MarkdownCodeBlockOptions,
  MarkdownDensity,
  MarkdownPresetComponentContext,
  MarkdownPresetConfig,
  MarkdownRenderMode,
  MarkdownRendererCoreProps,
  MarkdownSecurityProfile,
  MarkdownWidgetAction,
  MarkdownWidgetComponentProps,
  MarkdownWidgetContext,
  MarkdownWidgetDefinition,
  MarkdownWidgetFallbackProps,
  MarkdownWidgetPermission,
  MarkdownWidgetRegistry,
} from "./markdown-types";

.root :global(.inline-code) {
  background: var(--qv-md-inline-bg);
  padding: 0.2rem 0.5rem;
  border-radius: 0.375rem;
  font-size: 0.9em;
  font-family:
    "Fira Code", "Monaco", "Menlo", "Ubuntu Mono", "Consolas",
    "source-code-pro", monospace;
  font-weight: 500;
  color: var(--qv-md-inline-color);
  border: 1px solid var(--qv-md-inline-border);
  white-space: pre-wrap;
  overflow-wrap: break-word;
  word-break: break-word;
}

.root :global(.mermaid-block) {
  margin: 2rem 0;
  border-radius: 8px;
  border: 1px solid var(--qv-md-mermaid-border);
  box-shadow: 0 4px 12px var(--qv-md-mermaid-shadow);
}

.root :global(.mermaid-toolbar) {
  background: linear-gradient(
    to right,
    color-mix(in srgb, var(--qv-md-accent) 6%, transparent),
    color-mix(in srgb, var(--qv-md-secondary) 6%, transparent)
  );
  border-bottom: 1px solid var(--qv-md-mermaid-border);
}

.root :global(.mermaid-svg-container) {
  width: 100%;
  max-width: 100%;
  overflow-x: auto;
  display: flex;
  justify-content: center;
  scrollbar-width: thin;
  scrollbar-color: var(--qv-md-scrollbar-thumb) var(--qv-md-scrollbar-track);
}

.root :global(.mermaid-svg-container svg) {
  max-width: 100%;
  height: 100%;
}

.root :global(.mermaid-content),
.root :global(.mermaid-preview) {
  background: var(--qv-md-mermaid-bg);
}

.root :global(.mermaid-block .qiuye-code-block pre) {
  margin: 0;
  border-radius: 0;
  border: none;
  box-shadow: none;
}

.root :global(.mermaid-svg-container::-webkit-scrollbar) {
  height: 10px;
}

.root :global(.mermaid-svg-container::-webkit-scrollbar-track) {
  background: var(--qv-md-scrollbar-track);
  border-radius: 5px;
}

.root :global(.mermaid-svg-container::-webkit-scrollbar-thumb) {
  background: var(--qv-md-scrollbar-thumb);
  border-radius: 5px;
  transition: background 0.2s ease;
}

.root :global(.mermaid-svg-container::-webkit-scrollbar-thumb:hover) {
  background: var(--qv-md-scrollbar-thumb-hover);
}

.root :global(.mermaid-fullscreen-overlay .mermaid-svg-container) {
  width: 100%;
  height: 100%;
  max-width: none;
  overflow: visible;
  display: flex;
  align-items: center;
  justify-content: center;
  transform-origin: center center;
  user-select: none;
  -webkit-user-select: none;
}

.root :global(.mermaid-fullscreen-overlay .mermaid-svg-container svg) {
  max-width: 100%;
  max-height: 100%;
  width: auto;
  height: auto;
  filter: drop-shadow(0 4px 20px var(--qv-md-fullscreen-shadow));
}

.root :global(.mermaid-fullscreen-overlay button:focus) {
  outline: none;
  box-shadow: 0 0 0 2px var(--qv-md-focus-ring);
}

.root :global(.mermaid-fullscreen-overlay) {
  touch-action: none;
}

@media (max-width: 640px) {
  .root :global(.mermaid-block) {
    margin: 1.5rem 0;
    border-radius: 6px;
  }

  .root :global(.mermaid-preview) {
    padding: 1rem;
  }

  .root :global(.mermaid-svg-container svg) {
    min-width: 300px;
  }

  .root :global(.mermaid-fullscreen-overlay .mermaid-svg-container svg) {
    min-width: auto;
  }
}

"use client";

import React from "react";
import { MarkdownRendererCore } from "./MarkdownRendererCore";
import { blogPreset } from "./presets/blog-preset";
import type {
  MarkdownCodeBlockOptions,
  MarkdownWidgetRegistry,
  MarkdownWidgetContext,
} from "./markdown-types";
import type { Components } from "react-markdown";
import type {
  CodeBlockDisplayMode,
  CodeBlockColorThemeName,
  CodeBlockThemeConfig,
} from "@/components/qiuye-ui/code-block";
import type { PrismTheme } from "prism-react-renderer";

/** BlogMarkdownRenderer 组件的属性 */
export interface BlogMarkdownRendererProps {
  /** Markdown 原文内容 */
  content: string;
  /** 根容器额外类名 */
  className?: string;
  /** 代码块显示模式，透传给 CodeBlock */
  codeBlockDisplayMode?: CodeBlockDisplayMode;
  /** 折叠模式下的最大显示行数 */
  codeBlockMaxLines?: number;
  /** 滚动模式下的最大高度 */
  codeBlockMaxHeight?: string | number;
  /** 代码块横向滚动时是否固定行号列 */
  stickyLineNumbers?: boolean;
  /** 代码块内置配色主题名称 */
  codeBlockColorTheme?: CodeBlockColorThemeName;
  /** 自定义代码块主题配置 */
  codeBlockCustomTheme?: CodeBlockThemeConfig | PrismTheme;
  /** 覆盖 react-markdown components */
  components?: Components;
  /** Widget 注册表（博客场景一般不用） */
  widgetRegistry?: MarkdownWidgetRegistry;
  /** Widget 上下文 */
  widgetContext?: MarkdownWidgetContext;
}

/**
 * BlogMarkdownRenderer — 面向长文内容的 Markdown 渲染器
 *
 * 提供博客 / 文档场景的 Markdown 排版：
 * - 默认启用 GFM、原始 HTML、标题锚点与文章密度排版
 * - 使用 QiuYe UI CodeBlock 渲染代码块，支持标题和行高亮 meta
 * - 使用 ImageViewer 渲染图片，MermaidBlock 渲染 Mermaid 图表
 * - 可选接入 Widget 注册表扩展自定义内容块
 *
 * @example
 * ```tsx
 * <BlogMarkdownRenderer content={"# 标题\n\n正文内容"} />
 * ```
 */
export function BlogMarkdownRenderer({
  content,
  className = "",
  codeBlockDisplayMode,
  codeBlockMaxLines,
  codeBlockMaxHeight,
  stickyLineNumbers,
  codeBlockColorTheme,
  codeBlockCustomTheme,
  components,
  widgetRegistry,
  widgetContext,
}: BlogMarkdownRendererProps) {
  const codeBlock: MarkdownCodeBlockOptions = {
    displayMode: codeBlockDisplayMode,
    maxLines: codeBlockMaxLines,
    maxHeight: codeBlockMaxHeight,
    stickyLineNumbers: stickyLineNumbers,
    colorTheme: codeBlockColorTheme,
    customTheme: codeBlockCustomTheme,
  };

  return (
    <MarkdownRendererCore
      content={content}
      className={`markdown-renderer ${className}`}
      preset={blogPreset}
      codeBlock={codeBlock}
      components={components}
      widgetRegistry={widgetRegistry}
      widgetContext={widgetContext}
    />
  );
}

"use client";

import React from "react";
import { MarkdownRendererCore } from "./MarkdownRendererCore";
import { chatPreset } from "./presets/chat-preset";
import { builtinWidgetRegistry } from "./widgets/builtin-registry";
import type {
  MarkdownCodeBlockOptions,
  MarkdownWidgetRegistry,
  MarkdownWidgetContext,
} from "./markdown-types";
import type { Components } from "react-markdown";

/** ChatMarkdownRenderer 组件的属性 */
export interface ChatMarkdownRendererProps {
  /** Markdown 原文内容 */
  content: string;
  /** 根容器额外类名 */
  className?: string;
  /** 覆盖 react-markdown components */
  components?: Components;
  /** Widget 注册表，默认使用 builtin registry */
  widgetRegistry?: MarkdownWidgetRegistry;
  /** Widget 上下文 */
  widgetContext?: MarkdownWidgetContext;
  /** 代码块配置覆盖 */
  codeBlock?: MarkdownCodeBlockOptions;
  /** 是否启用原始 HTML（默认 false，untrusted） */
  enableRawHtml?: boolean;
}

/**
 * ChatMarkdownRenderer — 面向 AI 会话的 Markdown 渲染器
 *
 * 提供紧凑且更安全的会话渲染预设：
 * - 默认使用 untrusted 安全策略并禁用原始 HTML
 * - 代码块使用较小滚动高度，适合消息气泡或对话面板
 * - 内置 tool-call、artifact、reference-card 三类 Widget
 * - 链接和图片地址会经过安全清理与策略校验
 *
 * @example
 * ```tsx
 * <ChatMarkdownRenderer content={"我可以渲染 `inline code`。"} />
 * ```
 */
export function ChatMarkdownRenderer({
  content,
  className = "",
  components,
  widgetRegistry,
  widgetContext,
  codeBlock,
  enableRawHtml,
}: ChatMarkdownRendererProps) {
  const registry = widgetRegistry ?? builtinWidgetRegistry;

  return (
    <MarkdownRendererCore
      content={content}
      className={className}
      preset={chatPreset}
      codeBlock={codeBlock}
      components={components}
      widgetRegistry={registry}
      widgetContext={widgetContext}
      enableRawHtml={enableRawHtml}
    />
  );
}

"use client";

import React, { useState, useEffect, useRef, useMemo, useCallback } from "react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import rehypeRaw from "rehype-raw";
import type { Components } from "react-markdown";
import { useTheme } from "next-themes";
import { extractHeadingMeta, slugifyHeading } from "@/lib/heading-ids";
import { remarkCodeMeta } from "@/lib/markdown/remark-code-meta";
import {
  resolveCodeBlockTheme,
  type CodeBlockThemeConfig,
} from "@/components/qiuye-ui/code-block";
import type {
  MarkdownRendererCoreProps,
  MarkdownPresetConfig,
  MarkdownPresetComponentContext,
} from "./markdown-types";
import styles from "./markdown-renderer.module.css";

function getSyntaxColor(
  theme: CodeBlockThemeConfig,
  tokenType: string,
  fallback: string,
) {
  return (
    theme.syntax.styles.find((style) => style.types.includes(tokenType))?.style
      .color ?? fallback
  );
}

function alphaFromMode(isDark: boolean, darkAlpha: number, lightAlpha: number) {
  return isDark ? darkAlpha : lightAlpha;
}

/** MarkdownRendererCore 内部属性 */
export interface MarkdownRendererCoreInternalProps
  extends MarkdownRendererCoreProps {
  /** preset 配置，由 BlogMarkdownRenderer / ChatMarkdownRenderer 传入 */
  preset: MarkdownPresetConfig;
}

/**
 * MarkdownRendererCore — Markdown 渲染底座
 *
 * 负责组合解析插件、预设组件映射和运行时上下文：
 * - 统一接入 remark-gfm、remarkCodeMeta 与可选 rehypeRaw
 * - 根据 preset 合并代码块配置、密度、安全策略和组件映射
 * - 生成稳定标题 id，并支持关闭标题 id
 * - 将 Widget 注册表和上下文传递给 preset 组件
 *
 * @example
 * ```tsx
 * <MarkdownRendererCore content={content} preset={blogPreset} />
 * ```
 */
export function MarkdownRendererCore({
  content,
  className = "",
  components: componentOverrides,
  widgetRegistry,
  widgetContext,
  codeBlock: codeBlockOverride,
  enableHeadingIds: enableHeadingIdsOverride,
  enableRawHtml: enableRawHtmlOverride,
  preset,
}: MarkdownRendererCoreInternalProps) {
  const { resolvedTheme } = useTheme();
  const [mounted, setMounted] = useState(false);
  useEffect(() => {
    setMounted(true);
  }, []);

  const isDark = !mounted || resolvedTheme !== "light";
  const isDarkRef = useRef(isDark);
  isDarkRef.current = isDark;

  const enableHeadingIds = enableHeadingIdsOverride ?? preset.enableHeadingIds;
  const enableRawHtml = enableRawHtmlOverride ?? preset.enableRawHtml;
  const codeBlock = useMemo(() => {
    const overrideEntries = Object.entries(codeBlockOverride ?? {}).filter(
      ([, value]) => value !== undefined,
    );
    return {
      ...preset.codeBlock,
      ...Object.fromEntries(overrideEntries),
    };
  }, [preset.codeBlock, codeBlockOverride]);

  const markdownThemeStyle = useMemo(() => {
    const resolved = resolveCodeBlockTheme(
      codeBlock.colorTheme,
      codeBlock.customTheme,
      isDark,
    );
    const vars = resolved.vars;
    const syntax = resolved.syntax;
    const fg = syntax.plain.color ?? (isDark ? "#e6edf3" : "#24292f");
    const bg = syntax.plain.backgroundColor ?? vars.bg;
    const accent = getSyntaxColor(
      resolved,
      "keyword",
      isDark ? "#ff7b72" : "#cf222e",
    );
    const secondary = getSyntaxColor(
      resolved,
      "function",
      isDark ? "#d2a8ff" : "#8250df",
    );
    const inlineColor = getSyntaxColor(resolved, "string", accent);
    const muted = getSyntaxColor(resolved, "comment", vars.lnColor);
    const shadowAlpha = alphaFromMode(isDark, 0.3, 0.12);
    const fullscreenShadowAlpha = alphaFromMode(isDark, 0.45, 0.16);

    return {
      "--qv-md-bg": bg,
      "--qv-md-bg-rgb": vars.bgRgb,
      "--qv-md-fg": fg,
      "--qv-md-muted": muted,
      "--qv-md-accent": accent,
      "--qv-md-secondary": secondary,
      "--qv-md-inline-bg": vars.hover,
      "--qv-md-inline-color": inlineColor,
      "--qv-md-inline-border": vars.border,
      "--qv-md-mermaid-bg": bg,
      "--qv-md-mermaid-border": vars.border,
      "--qv-md-mermaid-shadow": `rgba(0, 0, 0, ${shadowAlpha})`,
      "--qv-md-scrollbar-track": vars.sbTrack,
      "--qv-md-scrollbar-thumb": vars.sbThumb,
      "--qv-md-scrollbar-thumb-hover": vars.sbThumbHover,
      "--qv-md-fullscreen-shadow": `rgba(0, 0, 0, ${fullscreenShadowAlpha})`,
      "--qv-md-focus-ring": vars.btnHoverBorder,
    } as React.CSSProperties;
  }, [codeBlock.colorTheme, codeBlock.customTheme, isDark]);

  const headingMeta = useMemo(
    () => (enableHeadingIds ? extractHeadingMeta(content, { maxLevel: 4 }) : []),
    [content, enableHeadingIds],
  );

  const headingIdByOffset = useMemo(() => {
    const map = new Map<number, string>();
    headingMeta.forEach((meta) => {
      if (typeof meta.offset === "number") {
        map.set(meta.offset, meta.id);
      }
    });
    return map;
  }, [headingMeta]);

  const getHeadingId = useCallback(
    (
      rawText: string,
      node?: { position?: { start?: { offset?: number } } },
    ) => {
      if (!enableHeadingIds) return undefined;

      const offset = node?.position?.start?.offset;
      if (typeof offset === "number") {
        const mappedId = headingIdByOffset.get(offset);
        if (mappedId) return mappedId;
      }

      const baseSlug = slugifyHeading(rawText);
      if (!baseSlug) {
        if (typeof offset === "number") {
          return `section-${offset}`;
        }
        return "section";
      }

      if (typeof offset === "number") {
        return `${baseSlug}-${offset}`;
      }

      return baseSlug;
    },
    [enableHeadingIds, headingIdByOffset],
  );

  const presetComponentCtx: MarkdownPresetComponentContext = useMemo(
    () => ({
      isDarkRef,
      getHeadingId,
      codeBlock,
      widgetRegistry,
      widgetContext,
      securityProfile: preset.securityProfile,
    }),
    [getHeadingId, codeBlock, widgetRegistry, widgetContext, preset.securityProfile],
  );

  const presetComponents = useMemo(
    () => preset.createComponents?.(presetComponentCtx) ?? {},
    [preset, presetComponentCtx],
  );

  const components: Components = useMemo(
    () => ({
      ...presetComponents,
      ...componentOverrides,
    }),
    [presetComponents, componentOverrides],
  );

  const rehypePlugins = useMemo(
    () => (enableRawHtml ? [rehypeRaw] : []),
    [enableRawHtml],
  );

  const modeClass = `qv-markdown qv-markdown--${preset.mode} qv-markdown--density-${preset.density}`;

  return (
    <div
      className={`${styles.root} ${modeClass} ${className}`}
      style={markdownThemeStyle}
    >
      <ReactMarkdown
        remarkPlugins={[remarkGfm, remarkCodeMeta]}
        rehypePlugins={rehypePlugins}
        components={components}
      >
        {content}
      </ReactMarkdown>
    </div>
  );
}

"use client";

import React from "react";
import type {
  MarkdownWidgetRegistry,
  MarkdownWidgetContext,
} from "./markdown-types";
import type { MarkdownWidgetInvocation } from "@/lib/markdown/parse-widget-fence";
import { WidgetErrorBoundary } from "./widgets/WidgetErrorBoundary";
import { UnknownWidget } from "./widgets/UnknownWidget";

interface MarkdownWidgetRendererProps {
  invocation: MarkdownWidgetInvocation;
  registry: MarkdownWidgetRegistry;
  context: MarkdownWidgetContext;
}

export function MarkdownWidgetRenderer({
  invocation,
  registry,
  context,
}: MarkdownWidgetRendererProps) {
  const { id, type, raw, propsRaw } = invocation;

  const definition = registry[type];
  if (!definition) {
    return <UnknownWidget type={type} id={id} raw={raw} />;
  }

  if (propsRaw === null) {
    return (
      <UnknownWidget
        type={type}
        id={id}
        raw={raw}
        reason="JSON 解析失败"
      />
    );
  }

  const parseResult = definition.parseProps(propsRaw);
  if (!parseResult.ok) {
    const FallbackComponent = definition.fallback;
    if (FallbackComponent) {
      return (
        <FallbackComponent
          id={id}
          type={type}
          raw={raw}
          reason={parseResult.reason}
          context={context}
        />
      );
    }
    return (
      <UnknownWidget
        type={type}
        id={id}
        raw={raw}
        reason={parseResult.reason}
      />
    );
  }

  const WidgetComponent = definition.component;

  return (
    <WidgetErrorBoundary widgetId={id} widgetType={type}>
      <div className="qv-widget my-3">
        <WidgetComponent
          id={id}
          type={type}
          props={parseResult.props}
          raw={raw}
          context={context}
        />
      </div>
    </WidgetErrorBoundary>
  );
}

"use client";

import React, {
  useState,
  useEffect,
  useRef,
  useId,
  useCallback,
  useMemo,
} from "react";
import {
  Code,
  Eye,
  AlertCircle,
  Maximize2,
  ZoomIn,
  ZoomOut,
  RotateCcw,
  X,
} from "lucide-react";
import { useTheme } from "next-themes";
import {
  CodeBlock,
  resolveCodeBlockTheme,
  type CodeBlockColorThemeName,
  type CodeBlockThemeConfig,
} from "@/components/qiuye-ui/code-block";
import type { PrismTheme } from "prism-react-renderer";
import {
  motion,
  useMotionValue,
  useMotionValueEvent,
  AnimatePresence,
  useReducedMotion,
} from "motion/react";
import { Button } from "@/components/ui/button";

// ============================================
// Mermaid 动态导入与主题
// ============================================

type MermaidAPI = typeof import("mermaid").default;
let mermaidPromise: Promise<MermaidAPI> | null = null;

function loadMermaid(): Promise<MermaidAPI> {
  if (!mermaidPromise) {
    mermaidPromise = import("mermaid").then((m) => m.default);
  }
  return mermaidPromise;
}

const MERMAID_FONT_FAMILY =
  '"Inter", "Fira Code", "Monaco", "Menlo", "Ubuntu Mono", "Consolas", "source-code-pro", monospace';

function getSyntaxColor(
  theme: CodeBlockThemeConfig,
  tokenType: string,
  fallback: string,
) {
  return (
    theme.syntax.styles.find((style) => style.types.includes(tokenType))?.style
      .color ?? fallback
  );
}

function getMermaidThemeVariables(
  theme: CodeBlockThemeConfig,
  isDark: boolean,
) {
  const bg = theme.syntax.plain.backgroundColor ?? theme.vars.bg;
  const fg = theme.syntax.plain.color ?? (isDark ? "#e6edf3" : "#24292f");
  const accent = getSyntaxColor(
    theme,
    "keyword",
    isDark ? "#ff7b72" : "#cf222e",
  );
  const secondary = getSyntaxColor(
    theme,
    "function",
    isDark ? "#d2a8ff" : "#8250df",
  );
  const muted = getSyntaxColor(
    theme,
    "comment",
    isDark ? "#8b949e" : "#6e7781",
  );

  return {
    darkMode: isDark,
    background: bg,
    primaryColor: theme.vars.hoverSolid,
    primaryTextColor: fg,
    primaryBorderColor: accent,
    lineColor: muted,
    secondaryColor: bg,
    tertiaryColor: bg,
    mainBkg: theme.vars.hoverSolid,
    nodeBorder: accent,
    clusterBkg: bg,
    clusterBorder: theme.vars.border,
    edgeLabelBackground: bg,
    textColor: fg,
    nodeTextColor: fg,
    titleColor: fg,
    noteBkgColor: theme.vars.hoverSolid,
    noteTextColor: fg,
    noteBorderColor: secondary,
  };
}

function getMermaidThemeCss(theme: CodeBlockThemeConfig, isDark: boolean): string {
  const bg = theme.syntax.plain.backgroundColor ?? theme.vars.bg;
  const nodeFill = theme.vars.hoverSolid;
  const nodeStroke = getSyntaxColor(
    theme,
    "keyword",
    isDark ? "#ff7b72" : "#cf222e",
  );
  const clusterFill = bg;
  const clusterStroke = theme.vars.border;
  const edgeLabelFill = bg;
  const edgeLabelStroke = theme.vars.border;

  return `
    .node rect,
    .cluster rect,
    .classGroup rect,
    .stateGroup rect,
    .note rect,
    .actor {
      rx: 10px;
      ry: 10px;
    }

    .node rect,
    .classGroup rect,
    .stateGroup rect,
    .note rect,
    .actor {
      fill: ${nodeFill};
      stroke: ${nodeStroke};
      stroke-width: 1.15px;
    }

    .cluster rect {
      fill: ${clusterFill};
      stroke: ${clusterStroke};
      stroke-width: 1.05px;
    }

    .edgeLabel rect,
    .label-container {
      fill: ${edgeLabelFill};
      stroke: ${edgeLabelStroke};
      rx: 8px;
      ry: 8px;
    }

    .flowchart-link,
    .edge-thickness-normal,
    .edge-thickness-thick,
    .messageLine0,
    .messageLine1 {
      stroke-linecap: round;
      stroke-linejoin: round;
    }
  `;
}

// ============================================
// MermaidBlock 组件
// ============================================

export interface MermaidBlockProps {
  children: string;
  stickyLineNumbers?: boolean;
  colorTheme?: CodeBlockColorThemeName;
  customTheme?: CodeBlockThemeConfig | PrismTheme;
}

export function MermaidBlock({
  children,
  stickyLineNumbers = true,
  colorTheme,
  customTheme,
}: MermaidBlockProps) {
  const code = children.trim();
  const [showPreview, setShowPreview] = useState(true);
  const [svgContent, setSvgContent] = useState<string>("");
  const [error, setError] = useState<string | null>(null);
  const [mounted, setMounted] = useState(false);
  const [isTouchDevice, setIsTouchDevice] = useState<boolean | null>(null);
  const { resolvedTheme } = useTheme();
  const isDark = !mounted || resolvedTheme !== "light";
  const resolvedMermaidTheme = useMemo(
    () => resolveCodeBlockTheme(colorTheme, customTheme, isDark),
    [colorTheme, customTheme, isDark],
  );
  const containerRef = useRef<HTMLDivElement>(null);
  const contentMeasureRef = useRef<HTMLDivElement>(null);
  const uniqueId = useId();
  const mermaidIdBase = `mermaid-${uniqueId.replace(/:/g, "-")}`;
  const renderCountRef = useRef(0);
  const [contentHeight, setContentHeight] = useState<number | "auto">("auto");

  const [isFullscreen, setIsFullscreen] = useState(false);
  const motionX = useMotionValue(0);
  const motionY = useMotionValue(0);
  const motionScale = useMotionValue(1);
  const prefersReducedMotion = useReducedMotion();
  const [scaleDisplay, setScaleDisplay] = useState(100);
  const isDraggingRef = useRef(false);
  const dragStartRef = useRef({ x: 0, y: 0 });
  const positionStartRef = useRef({ x: 0, y: 0 });
  const svgContainerRef = useRef<HTMLDivElement>(null);
  const pinchStartDistanceRef = useRef(0);
  const pinchStartScaleRef = useRef(1);

  const MIN_SCALE = 0.25;
  const MAX_SCALE = 4;
  const SCALE_STEP = 0.25;
  const fullscreenEase: [number, number, number, number] = [0.22, 1, 0.36, 1];
  const fullscreenOverlayTransition = prefersReducedMotion
    ? { duration: 0.14, ease: "linear" as const }
    : { duration: 0.28, ease: fullscreenEase };
  const fullscreenPanelTransition = prefersReducedMotion
    ? { duration: 0.16, ease: "linear" as const }
    : { duration: 0.36, ease: fullscreenEase };
  const fullscreenOverlayExitTransition = prefersReducedMotion
    ? { duration: 0.12, ease: "linear" as const }
    : { duration: 0.18, ease: fullscreenEase };
  const fullscreenPanelExitTransition = prefersReducedMotion
    ? { duration: 0.12, ease: "linear" as const }
    : { duration: 0.2, ease: fullscreenEase };
  const contentHeightTransition = prefersReducedMotion
    ? { duration: 0 }
    : { duration: 0.42, ease: fullscreenEase };

  useMotionValueEvent(motionScale, "change", (latest) => {
    const displayValue = Math.round(latest * 100);
    setScaleDisplay((prev) =>
      Math.abs(prev - displayValue) >= 1 ? displayValue : prev,
    );
  });

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (!mounted) return;

    const element = contentMeasureRef.current;
    if (!element || typeof ResizeObserver === "undefined") return;

    let frameId = 0;
    const updateHeight = () => {
      const nextHeight = element.getBoundingClientRect().height;
      if (nextHeight <= 0) return;

      setContentHeight((prevHeight) => {
        if (
          typeof prevHeight === "number" &&
          Math.abs(prevHeight - nextHeight) < 0.5
        ) {
          return prevHeight;
        }

        return nextHeight;
      });
    };

    updateHeight();

    const resizeObserver = new ResizeObserver(() => {
      cancelAnimationFrame(frameId);
      frameId = requestAnimationFrame(updateHeight);
    });
    resizeObserver.observe(element);

    return () => {
      cancelAnimationFrame(frameId);
      resizeObserver.disconnect();
    };
  }, [mounted]);

  useEffect(() => {
    if (!mounted) return;

    const hoverFineQuery = window.matchMedia(
      "(hover: hover) and (pointer: fine)",
    );
    const coarsePointerQuery = window.matchMedia("(pointer: coarse)");

    const updateDeviceMode = () => {
      const hasTouchInput = navigator.maxTouchPoints > 0;
      setIsTouchDevice(
        coarsePointerQuery.matches ||
          (hasTouchInput && !hoverFineQuery.matches),
      );
    };

    updateDeviceMode();
    hoverFineQuery.addEventListener("change", updateDeviceMode);
    coarsePointerQuery.addEventListener("change", updateDeviceMode);

    return () => {
      hoverFineQuery.removeEventListener("change", updateDeviceMode);
      coarsePointerQuery.removeEventListener("change", updateDeviceMode);
    };
  }, [mounted]);

  useEffect(() => {
    if (!mounted || !showPreview) return;

    let cancelled = false;

    const initAndRender = async () => {
      try {
        setError(null);

        const mermaid = await loadMermaid();
        if (cancelled) return;

        mermaid.initialize({
          startOnLoad: false,
          theme: "base",
          securityLevel: "loose",
          htmlLabels: true,
          fontFamily: MERMAID_FONT_FAMILY,
          flowchart: {
            curve: "natural",
          },
          themeVariables: getMermaidThemeVariables(resolvedMermaidTheme, isDark),
          themeCSS: getMermaidThemeCss(resolvedMermaidTheme, isDark),
        });

        const isValid = await mermaid.parse(code);
        if (cancelled) return;

        if (!isValid) {
          setError("Mermaid 语法验证失败");
          return;
        }

        renderCountRef.current += 1;
        const mermaidId = `${mermaidIdBase}-${renderCountRef.current}`;
        const { svg } = await mermaid.render(mermaidId, code);
        if (cancelled) return;

        setSvgContent(svg);
      } catch (err) {
        if (cancelled) return;
        console.error("Mermaid render error:", err);
        setError(err instanceof Error ? err.message : "Mermaid 渲染失败");
      }
    };

    initAndRender();

    return () => {
      cancelled = true;
    };
  }, [
    mounted,
    code,
    showPreview,
    mermaidIdBase,
    resolvedMermaidTheme,
    isDark,
  ]);

  useEffect(() => {
    if (!isFullscreen) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        isDraggingRef.current = false;
        setIsFullscreen(false);
      }
    };

    const handleGlobalWheel = (e: WheelEvent) => {
      if (e.ctrlKey) {
        e.preventDefault();
      }
    };

    const handleGestureStart = (e: Event) => {
      e.preventDefault();
    };

    const handleGestureChange = (e: Event) => {
      e.preventDefault();
      const gestureEvent = e as Event & { scale?: number };
      if (gestureEvent.scale !== undefined) {
        const newScale = Math.min(
          Math.max(gestureEvent.scale, MIN_SCALE),
          MAX_SCALE,
        );
        motionScale.set(newScale);
      }
    };

    const handleGestureEnd = (e: Event) => {
      e.preventDefault();
    };

    document.addEventListener("keydown", handleKeyDown);
    document.addEventListener("wheel", handleGlobalWheel, { passive: false });
    document.addEventListener("gesturestart", handleGestureStart);
    document.addEventListener("gesturechange", handleGestureChange);
    document.addEventListener("gestureend", handleGestureEnd);

    document.body.style.overflow = "hidden";

    return () => {
      document.removeEventListener("keydown", handleKeyDown);
      document.removeEventListener("wheel", handleGlobalWheel);
      document.removeEventListener("gesturestart", handleGestureStart);
      document.removeEventListener("gesturechange", handleGestureChange);
      document.removeEventListener("gestureend", handleGestureEnd);
      document.body.style.overflow = "";
    };
  }, [isFullscreen, motionScale, motionX, motionY]);

  const resetTransform = useCallback(() => {
    motionScale.set(1);
    motionX.set(0);
    motionY.set(0);
    setScaleDisplay(100);
  }, [motionScale, motionX, motionY]);

  const handleZoomIn = useCallback(() => {
    const newScale = Math.min(motionScale.get() + SCALE_STEP, MAX_SCALE);
    motionScale.set(newScale);
  }, [motionScale]);

  const handleZoomOut = useCallback(() => {
    const newScale = Math.max(motionScale.get() - SCALE_STEP, MIN_SCALE);
    motionScale.set(newScale);
  }, [motionScale]);

  const handleWheel = useCallback(
    (e: React.WheelEvent) => {
      if (!isFullscreen) return;
      e.preventDefault();

      const currentScale = motionScale.get();

      if (e.ctrlKey) {
        const zoomFactor = 1 - e.deltaY * 0.01;
        const newScale = Math.min(
          Math.max(currentScale * zoomFactor, MIN_SCALE),
          MAX_SCALE,
        );
        motionScale.set(newScale);
      } else {
        const delta = e.deltaY > 0 ? -SCALE_STEP : SCALE_STEP;
        const newScale = Math.min(
          Math.max(currentScale + delta, MIN_SCALE),
          MAX_SCALE,
        );
        motionScale.set(newScale);
      }
    },
    [isFullscreen, motionScale],
  );

  const handleMouseDown = useCallback(
    (e: React.MouseEvent) => {
      if (!isFullscreen) return;
      e.preventDefault();
      isDraggingRef.current = true;
      dragStartRef.current = { x: e.clientX, y: e.clientY };
      positionStartRef.current = { x: motionX.get(), y: motionY.get() };
    },
    [isFullscreen, motionX, motionY],
  );

  const handleMouseMove = useCallback(
    (e: React.MouseEvent) => {
      if (!isDraggingRef.current || !isFullscreen) return;

      const deltaX = e.clientX - dragStartRef.current.x;
      const deltaY = e.clientY - dragStartRef.current.y;

      motionX.set(positionStartRef.current.x + deltaX);
      motionY.set(positionStartRef.current.y + deltaY);
    },
    [isFullscreen, motionX, motionY],
  );

  const handleMouseUp = useCallback(() => {
    isDraggingRef.current = false;
  }, []);

  const getTouchDistance = useCallback((touches: React.TouchList) => {
    const dx = touches[0].clientX - touches[1].clientX;
    const dy = touches[0].clientY - touches[1].clientY;
    return Math.sqrt(dx * dx + dy * dy);
  }, []);

  const handleTouchStart = useCallback(
    (e: React.TouchEvent) => {
      if (!isFullscreen) return;

      if (e.touches.length === 1) {
        isDraggingRef.current = true;
        dragStartRef.current = {
          x: e.touches[0].clientX,
          y: e.touches[0].clientY,
        };
        positionStartRef.current = { x: motionX.get(), y: motionY.get() };
      } else if (e.touches.length === 2) {
        isDraggingRef.current = false;
        pinchStartDistanceRef.current = getTouchDistance(e.touches);
        pinchStartScaleRef.current = motionScale.get();
      }
    },
    [isFullscreen, motionX, motionY, motionScale, getTouchDistance],
  );

  const handleTouchMove = useCallback(
    (e: React.TouchEvent) => {
      if (!isFullscreen) return;

      if (e.touches.length === 1 && isDraggingRef.current) {
        const deltaX = e.touches[0].clientX - dragStartRef.current.x;
        const deltaY = e.touches[0].clientY - dragStartRef.current.y;

        motionX.set(positionStartRef.current.x + deltaX);
        motionY.set(positionStartRef.current.y + deltaY);
      } else if (e.touches.length === 2) {
        const currentDistance = getTouchDistance(e.touches);
        const scaleRatio = currentDistance / pinchStartDistanceRef.current;
        const newScale = Math.min(
          Math.max(pinchStartScaleRef.current * scaleRatio, MIN_SCALE),
          MAX_SCALE,
        );

        motionScale.set(newScale);
      }
    },
    [isFullscreen, motionX, motionY, motionScale, getTouchDistance],
  );

  const handleTouchEnd = useCallback(() => {
    isDraggingRef.current = false;
  }, []);

  const enterFullscreen = useCallback(() => {
    motionScale.set(1);
    motionX.set(0);
    motionY.set(0);
    setScaleDisplay(100);
    setIsFullscreen(true);
  }, [motionScale, motionX, motionY]);

  const exitFullscreen = useCallback(() => {
    isDraggingRef.current = false;
    setIsFullscreen(false);
  }, []);

  if (!mounted) {
    return (
      <div className="mermaid-block rounded-lg bg-muted/20 p-4">
        <div className="flex items-center justify-center py-8 text-muted-foreground">
          加载中...
        </div>
      </div>
    );
  }

  const renderSvgContent = () => {
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center gap-2 text-destructive">
          <AlertCircle className="h-6 w-6" />
          <span className="text-sm">{error}</span>
        </div>
      );
    }

    if (!svgContent) {
      return (
        <div className="flex items-center justify-center py-4 text-muted-foreground text-sm">
          渲染中...
        </div>
      );
    }

    return (
      <div
        className="mermaid-svg-container pointer-events-none"
        dangerouslySetInnerHTML={{ __html: svgContent }}
      />
    );
  };

  const renderFullscreenSvgContent = () => {
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center gap-2 text-destructive">
          <AlertCircle className="h-6 w-6" />
          <span className="text-sm">{error}</span>
        </div>
      );
    }

    if (!svgContent) {
      return (
        <div className="flex items-center justify-center py-4 text-muted-foreground text-sm">
          渲染中...
        </div>
      );
    }

    return (
      <motion.div
        ref={svgContainerRef}
        className="mermaid-svg-container pointer-events-none cursor-grab"
        style={{
          x: motionX,
          y: motionY,
          scale: motionScale,
        }}
        dangerouslySetInnerHTML={{ __html: svgContent }}
      />
    );
  };

  const fullscreenToolbarSurfaceClass =
    "pointer-events-auto rounded-2xl border border-border/40 bg-background/72 shadow-lg shadow-black/5 backdrop-blur-md";
  const showFullscreenDesktopHint = isTouchDevice === false;
  const showFullscreenTouchExitButton = isTouchDevice === true;

  const fullscreenToolbarInfo = (
    <div className="flex items-center gap-2">
      <span className="text-sm font-medium text-muted-foreground">
        Mermaid 图表预览
      </span>
      <span className="text-xs text-muted-foreground/60">{scaleDisplay}%</span>
    </div>
  );

  const fullscreenToolbarControls = (
    <div className="flex items-center gap-1">
      <button
        onClick={handleZoomOut}
        disabled={scaleDisplay <= MIN_SCALE * 100}
        className="p-2 rounded-md text-muted-foreground cursor-pointer hover:text-foreground hover:bg-muted/50 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
        title="缩小"
      >
        <ZoomOut className="h-4 w-4" />
      </button>
      <button
        onClick={handleZoomIn}
        disabled={scaleDisplay >= MAX_SCALE * 100}
        className="p-2 rounded-md text-muted-foreground cursor-pointer hover:text-foreground hover:bg-muted/50 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
        title="放大"
      >
        <ZoomIn className="h-4 w-4" />
      </button>
      <button
        onClick={resetTransform}
        className="p-2 rounded-md text-muted-foreground cursor-pointer hover:text-foreground hover:bg-muted/50 transition-colors"
        title="重置视图"
      >
        <RotateCcw className="h-4 w-4" />
      </button>
      <div className="w-px h-4 bg-border/50 mx-1" />
      <button
        onClick={exitFullscreen}
        className="p-2 rounded-md text-muted-foreground cursor-pointer hover:text-foreground hover:bg-muted/50 transition-colors"
        title="退出预览 (ESC)"
      >
        <X className="h-4 w-4" />
      </button>
    </div>
  );

  return (
    <>
      <div className="mermaid-block rounded-lg overflow-hidden">
        <div className="mermaid-toolbar flex items-center justify-between pl-4 pr-2 py-2 bg-muted/30">
          <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
            Mermaid
          </span>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setShowPreview(false)}
              className={`relative flex items-center gap-1.5 px-2.5 py-1 rounded-md text-xs font-medium transition-colors ${
                !showPreview
                  ? "text-primary"
                  : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
              }`}
              title="查看源码"
            >
              {!showPreview && (
                <motion.span
                  layoutId={`${mermaidIdBase}-tab-bg`}
                  className="absolute inset-0 bg-primary/10 rounded-md"
                  transition={{ type: "spring", bounce: 0.2, duration: 0.4 }}
                />
              )}
              <Code className="relative h-3.5 w-3.5" />
              <span className="relative">代码</span>
            </button>
            <button
              onClick={() => setShowPreview(true)}
              className={`relative flex items-center gap-1.5 px-2.5 py-1 rounded-md text-xs font-medium transition-colors ${
                showPreview
                  ? "text-primary"
                  : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
              }`}
              title="查看预览"
            >
              {showPreview && (
                <motion.span
                  layoutId={`${mermaidIdBase}-tab-bg`}
                  className="absolute inset-0 bg-primary/10 rounded-md"
                  transition={{ type: "spring", bounce: 0.2, duration: 0.4 }}
                />
              )}
              <Eye className="relative h-3.5 w-3.5" />
              <span className="relative">预览</span>
            </button>
          </div>
        </div>

        <motion.div
          className="mermaid-content group/mermaid relative overflow-hidden"
          animate={{ height: contentHeight }}
          transition={contentHeightTransition}
        >
          <div ref={contentMeasureRef} className="relative">
            <AnimatePresence mode="popLayout" initial={false}>
              {showPreview ? (
                <motion.div
                  key="preview"
                  initial={{ opacity: 0, x: "50%" }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: "50%" }}
                  transition={{ duration: 0.5, type: "spring", bounce: 0 }}
                  ref={containerRef}
                  className="mermaid-preview relative flex justify-center p-6 min-h-[120px]"
                >
                  {renderSvgContent()}
                  {svgContent && !error && (
                    <Button
                      size="icon"
                      variant="ghost"
                      onClick={enterFullscreen}
                      className="absolute top-2 right-2 size-8 md:opacity-0 md:group-hover/mermaid:opacity-100"
                      title="全屏查看"
                    >
                      <Maximize2 className="h-4 w-4" />
                    </Button>
                  )}
                </motion.div>
              ) : (
                <motion.div
                  key="code"
                  initial={{ opacity: 0, x: "-50%" }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: "-50%" }}
                  transition={{ duration: 0.5, type: "spring", bounce: 0 }}
                >
                  <CodeBlock
                    language="mermaid"
                    isDark={isDark}
                    stickyLineNumbers={stickyLineNumbers}
                    colorTheme={colorTheme}
                    customTheme={customTheme}
                  >
                    {code}
                  </CodeBlock>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </motion.div>
      </div>

      <AnimatePresence initial={false} onExitComplete={resetTransform}>
        {isFullscreen && (
          <motion.div
            key="mermaid-fullscreen"
            className="mermaid-fullscreen-overlay fixed inset-0 z-[9999] overflow-hidden"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1, transition: fullscreenOverlayTransition }}
            exit={{ opacity: 0, transition: fullscreenOverlayExitTransition }}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
            onTouchMove={handleTouchMove}
            onTouchEnd={handleTouchEnd}
            role="dialog"
            aria-modal="true"
            aria-label="Mermaid 图表全屏预览"
          >
            <motion.div
              className="absolute inset-0 bg-background/95 backdrop-blur-sm"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1, transition: fullscreenOverlayTransition }}
              exit={{ opacity: 0, transition: fullscreenOverlayExitTransition }}
            />

            <motion.div
              className="absolute inset-0 bg-[radial-gradient(circle_at_top,rgba(124,167,255,0.08),transparent_45%),radial-gradient(circle_at_bottom,rgba(214,200,166,0.08),transparent_42%)]"
              initial={{ opacity: 0 }}
              animate={{
                opacity: 1,
                transition: {
                  ...fullscreenOverlayTransition,
                  delay: prefersReducedMotion ? 0 : 0.03,
                },
              }}
              exit={{ opacity: 0, transition: fullscreenOverlayExitTransition }}
            />

            <div className="pointer-events-none absolute inset-x-0 top-[4.5rem] z-[10000] px-3 sm:px-4">
              <motion.div
                className={`flex items-center justify-between px-4 py-3 md:hidden ${fullscreenToolbarSurfaceClass}`}
                initial={{
                  opacity: 0,
                  y: prefersReducedMotion ? 0 : -18,
                  filter: prefersReducedMotion ? "blur(0px)" : "blur(10px)",
                }}
                animate={{
                  opacity: 1,
                  y: 0,
                  filter: "blur(0px)",
                  transition: {
                    ...fullscreenPanelTransition,
                    delay: prefersReducedMotion ? 0 : 0.04,
                  },
                }}
                exit={{
                  opacity: 0,
                  y: prefersReducedMotion ? 0 : -12,
                  filter: prefersReducedMotion ? "blur(0px)" : "blur(8px)",
                  transition: fullscreenPanelExitTransition,
                }}
              >
                {fullscreenToolbarInfo}
                {fullscreenToolbarControls}
              </motion.div>

              <div className="hidden md:flex items-start justify-between gap-4">
                <motion.div
                  className={`w-fit px-4 py-3 ${fullscreenToolbarSurfaceClass}`}
                  initial={{
                    opacity: 0,
                    x: prefersReducedMotion ? 0 : -16,
                    y: prefersReducedMotion ? 0 : -18,
                    filter: prefersReducedMotion ? "blur(0px)" : "blur(10px)",
                  }}
                  animate={{
                    opacity: 1,
                    x: 0,
                    y: 0,
                    filter: "blur(0px)",
                    transition: {
                      ...fullscreenPanelTransition,
                      delay: prefersReducedMotion ? 0 : 0.04,
                    },
                  }}
                  exit={{
                    opacity: 0,
                    x: prefersReducedMotion ? 0 : -10,
                    y: prefersReducedMotion ? 0 : -12,
                    filter: prefersReducedMotion ? "blur(0px)" : "blur(8px)",
                    transition: fullscreenPanelExitTransition,
                  }}
                >
                  {fullscreenToolbarInfo}
                </motion.div>

                <motion.div
                  className={`w-fit px-3 py-2 ${fullscreenToolbarSurfaceClass}`}
                  initial={{
                    opacity: 0,
                    x: prefersReducedMotion ? 0 : 16,
                    y: prefersReducedMotion ? 0 : -18,
                    filter: prefersReducedMotion ? "blur(0px)" : "blur(10px)",
                  }}
                  animate={{
                    opacity: 1,
                    x: 0,
                    y: 0,
                    filter: "blur(0px)",
                    transition: {
                      ...fullscreenPanelTransition,
                      delay: prefersReducedMotion ? 0 : 0.08,
                    },
                  }}
                  exit={{
                    opacity: 0,
                    x: prefersReducedMotion ? 0 : 10,
                    y: prefersReducedMotion ? 0 : -12,
                    filter: prefersReducedMotion ? "blur(0px)" : "blur(8px)",
                    transition: fullscreenPanelExitTransition,
                  }}
                >
                  {fullscreenToolbarControls}
                </motion.div>
              </div>
            </div>

            <div
              className="absolute top-0 bottom-0 left-0 w-screen overflow-hidden px-4 pt-20 pb-20 sm:px-6 sm:pb-24"
              onWheel={handleWheel}
              onMouseDown={handleMouseDown}
              onTouchStart={handleTouchStart}
            >
              <motion.div
                className="flex h-full w-full items-center justify-center"
                initial={{
                  opacity: 0,
                  y: prefersReducedMotion ? 0 : 20,
                  scale: prefersReducedMotion ? 1 : 0.985,
                  filter: prefersReducedMotion ? "blur(0px)" : "blur(14px)",
                }}
                animate={{
                  opacity: 1,
                  y: 0,
                  scale: 1,
                  filter: "blur(0px)",
                  transition: {
                    ...fullscreenPanelTransition,
                    delay: prefersReducedMotion ? 0 : 0.06,
                  },
                }}
                exit={{
                  opacity: 0,
                  y: prefersReducedMotion ? 0 : 16,
                  scale: prefersReducedMotion ? 1 : 0.99,
                  filter: prefersReducedMotion ? "blur(0px)" : "blur(10px)",
                  transition: fullscreenPanelExitTransition,
                }}
              >
                {renderFullscreenSvgContent()}
              </motion.div>
            </div>

            {showFullscreenDesktopHint && (
              <motion.div
                className="absolute bottom-4 left-4 flex items-center gap-4 rounded-full border border-border/35 bg-muted/45 px-4 py-2 text-xs text-muted-foreground backdrop-blur-md"
                initial={{
                  opacity: 0,
                  y: prefersReducedMotion ? 0 : 14,
                  filter: prefersReducedMotion ? "blur(0px)" : "blur(8px)",
                }}
                animate={{
                  opacity: 1,
                  y: 0,
                  filter: "blur(0px)",
                  transition: {
                    ...fullscreenPanelTransition,
                    delay: prefersReducedMotion ? 0 : 0.1,
                  },
                }}
                exit={{
                  opacity: 0,
                  y: prefersReducedMotion ? 0 : 10,
                  filter: prefersReducedMotion ? "blur(0px)" : "blur(6px)",
                  transition: fullscreenPanelExitTransition,
                }}
              >
                <span>滚轮缩放</span>
                <span className="w-px h-3 bg-border/50" />
                <span>拖拽移动</span>
                <span className="w-px h-3 bg-border/50" />
                <span>ESC 退出</span>
              </motion.div>
            )}

            {showFullscreenTouchExitButton && (
              <motion.div
                className="pointer-events-none absolute inset-x-0 bottom-8 z-[10000] flex justify-center px-4"
                initial={{
                  opacity: 0,
                  y: prefersReducedMotion ? 0 : 14,
                  filter: prefersReducedMotion ? "blur(0px)" : "blur(8px)",
                }}
                animate={{
                  opacity: 1,
                  y: 0,
                  filter: "blur(0px)",
                  transition: {
                    ...fullscreenPanelTransition,
                    delay: prefersReducedMotion ? 0 : 0.1,
                  },
                }}
                exit={{
                  opacity: 0,
                  y: prefersReducedMotion ? 0 : 10,
                  filter: prefersReducedMotion ? "blur(0px)" : "blur(6px)",
                  transition: fullscreenPanelExitTransition,
                }}
              >
                <Button
                  type="button"
                  variant="outline"
                  onClick={exitFullscreen}
                  className="pointer-events-auto h-11 rounded-full border-border/40 bg-background/78 px-5 text-sm text-foreground shadow-lg shadow-black/5 backdrop-blur-md hover:bg-background/88"
                >
                  <X className="h-4 w-4" />
                  退出预览
                </Button>
              </motion.div>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

