export interface HeadingMeta {
  id: string;
  text: string;
  level: number;
  index: number;
  offset?: number;
}

export function slugifyHeading(text: string) {
  return text
    .toLowerCase()
    .replace(/[^\w\u4e00-\u9fa5]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .replace(/-{2,}/g, "-")
    .trim();
}

interface ExtractHeadingMetaOptions {
  maxLevel?: number;
}

export function extractHeadingMeta(
  content: string,
  options: ExtractHeadingMetaOptions = {}
): HeadingMeta[] {
  const { maxLevel = 6 } = options;

  const headingRegex = /^(#{1,6})\s+(.+)$/;
  const occurrences = new Map<string, number>();
  const headingMeta: HeadingMeta[] = [];
  let fallbackIndex = 1;
  let inCodeBlock = false;
  let offset = 0;

  const lines = content.split("\n");

  for (const line of lines) {
    const trimmedLine = line.trim();
    if (trimmedLine.startsWith("```")) {
      inCodeBlock = !inCodeBlock;
      offset += line.length + 1;
      continue;
    }

    if (!inCodeBlock) {
      const cleanedLine = line.replace(/`+/g, "");
      const match = headingRegex.exec(cleanedLine);
      if (match) {
        const level = match[1].length;

        if (level <= maxLevel) {
          const text = match[2].trim();
          let baseSlug = slugifyHeading(text);

          if (!baseSlug) {
            baseSlug = `section-${fallbackIndex}`;
            fallbackIndex += 1;
          }

          const currentCount = occurrences.get(baseSlug) ?? 0;
          occurrences.set(baseSlug, currentCount + 1);

          const id =
            currentCount === 0 ? baseSlug : `${baseSlug}-${currentCount + 1}`;
          const hashIndex = line.indexOf(match[1]);

          headingMeta.push({
            id,
            text,
            level,
            index: headingMeta.length,
            offset: offset + Math.max(0, hashIndex),
          });
        }
      }
    }

    offset += line.length + 1;
  }

  return headingMeta;
}

const SAFE_PROTOCOLS = ["http:", "https:", "mailto:"];

/**
 * 检查 URL 是否符合安全策略。
 * - trusted：允许所有 URL。
 * - untrusted：只允许 http / https / mailto 和站内相对路径。
 */
export function isUrlAllowed(
  url: string | undefined,
  profile: "trusted" | "untrusted",
): boolean {
  if (!url) return false;
  if (profile === "trusted") return true;

  if (url.startsWith("/") || url.startsWith("#") || url.startsWith("?")) {
    return true;
  }

  try {
    const parsed = new URL(url);
    return SAFE_PROTOCOLS.includes(parsed.protocol);
  } catch {
    return false;
  }
}

/**
 * 为外部链接添加安全属性
 */
export function getSafeLinkProps(
  href: string | undefined,
  profile: "trusted" | "untrusted",
): Record<string, string> {
  if (!href) return {};

  const isExternal =
    href.startsWith("http://") || href.startsWith("https://");

  if (isExternal || profile === "untrusted") {
    return {
      target: "_blank",
      rel: "noopener noreferrer",
    };
  }

  return {};
}

/**
 * 从代码块的 meta 字符串中解析 title、highlightLines 等属性
 *
 * 支持的语法:
 * - title:  ```tsx title="filename.tsx"  /  title='...'  /  title=...
 * - 行高亮: ```tsx {1,3,5-10}  （花括号内为逗号分隔的行号或范围）
 *
 * 两者可任意组合、顺序不限:
 *   ```tsx title="App.tsx" {3,7-9}
 *   ```tsx {1,4-6} title="utils.ts"
 */
export function parseCodeBlockMeta(meta: string | undefined | null): {
  title?: string;
  highlightLines?: string;
} {
  if (!meta) return {};
  const result: { title?: string; highlightLines?: string } = {};

  const titleMatch = meta.match(/title\s*=\s*(?:"([^"]*)"|'([^']*)'|(\S+))/);
  if (titleMatch) {
    result.title = titleMatch[1] ?? titleMatch[2] ?? titleMatch[3];
  }

  const highlightMatch = meta.match(/\{([\d,\s-]+)\}/);
  if (highlightMatch) {
    result.highlightLines = highlightMatch[1].trim();
  }

  return result;
}

export interface MarkdownWidgetInvocation {
  id: string;
  type: string;
  version: number;
  raw: string;
  propsRaw: unknown;
  source?: {
    offset?: number;
    line?: number;
    column?: number;
  };
}

/**
 * 解析 widget fenced code block 的语言、meta 和内容，
 * 返回 MarkdownWidgetInvocation 或 null。
 *
 * 支持的语法：
 * - ```qv-widget type="tool-call" version="1" id="search-1"
 * - ```qv:reference-card id="ref-1"
 */
export function parseWidgetFence(
  language: string,
  meta: string | undefined | null,
  rawBody: string,
): MarkdownWidgetInvocation | null {
  let type: string | undefined;

  if (language === "qv-widget") {
    type = extractMetaValue(meta, "type");
    if (!type) return null;
  } else if (language.startsWith("qv:")) {
    type = language.slice(3);
    const metaType = extractMetaValue(meta, "type");
    if (metaType) type = metaType;
  } else {
    return null;
  }

  if (!type) return null;

  const id =
    extractMetaValue(meta, "id") || `widget-${type}-${simpleHash(rawBody)}`;
  const versionStr = extractMetaValue(meta, "version");
  const version = versionStr ? parseInt(versionStr, 10) || 1 : 1;

  let propsRaw: unknown = null;
  const trimmed = rawBody.trim();
  if (trimmed) {
    try {
      propsRaw = JSON.parse(trimmed);
    } catch {
      return {
        id,
        type,
        version,
        raw: rawBody,
        propsRaw: null,
      };
    }
  }

  return {
    id,
    type,
    version,
    raw: rawBody,
    propsRaw,
  };
}

function extractMetaValue(
  meta: string | undefined | null,
  key: string,
): string | undefined {
  if (!meta) return undefined;
  const regex = new RegExp(`${key}\\s*=\\s*(?:"([^"]*)"|'([^']*)'|(\\S+))`);
  const match = meta.match(regex);
  if (!match) return undefined;
  return match[1] ?? match[2] ?? match[3];
}

function simpleHash(str: string): string {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash + char) | 0;
  }
  return Math.abs(hash).toString(36);
}

/** Remark AST 节点最小接口 */
export interface MdastNode {
  type: string;
  meta?: string;
  data?: {
    hProperties?: Record<string, unknown>;
    [key: string]: unknown;
  };
  children?: MdastNode[];
}

/**
 * Remark 插件：将代码块的 meta 信息透传到 HTML 元素属性
 *
 * Markdown 中 fenced code block 支持在语言标识后附加 meta 信息，
 * 例如 ```tsx title="App.tsx"。remark 默认不会将 meta 传递到 HTML 元素。
 * 此插件通过 hProperties 将 meta 注入为 data-meta 属性，
 * 使 react-markdown 的自定义组件能够读取和解析。
 */
export function remarkCodeMeta() {
  return (tree: MdastNode) => {
    function walk(node: MdastNode) {
      if (node.type === "code" && node.meta) {
        node.data = node.data || {};
        const hProperties = (node.data.hProperties || {}) as Record<
          string,
          unknown
        >;
        hProperties["data-meta"] = node.meta;
        node.data.hProperties = hProperties;
      }
      if (node.children) {
        node.children.forEach(walk);
      }
    }
    walk(tree);
  };
}

const JAVASCRIPT_PROTOCOL = /^javascript:/i;
const DATA_PROTOCOL = /^data:/i;
const VBSCRIPT_PROTOCOL = /^vbscript:/i;

/**
 * 清理 URL，移除危险协议。
 * 返回安全的 URL 字符串，或空字符串。
 */
export function sanitizeUrl(url: string | Blob | undefined | null): string {
  if (!url) return "";
  if (typeof url !== "string") return "";

  const trimmed = url.trim();

  if (
    JAVASCRIPT_PROTOCOL.test(trimmed) ||
    VBSCRIPT_PROTOCOL.test(trimmed)
  ) {
    return "";
  }

  if (DATA_PROTOCOL.test(trimmed)) {
    if (trimmed.startsWith("data:image/")) {
      return trimmed;
    }
    return "";
  }

  return trimmed;
}
